import stringfrom agent import *from models.products import *import redebug = Truedef process_view_category(data, context, session):    for view_categoryline in data.xpath("//p/a[contains(@href,'/reviews/')]"):         url = view_categoryline.xpath("(.)/@href").string()        name = view_categoryline.xpath("(.)/text()").string()        if url and name:           session.queue(Request(url), process_view_product, {'url': url, 'name': name })    #nexturl = data.xpath("//a[contains(@title,'dalej')]//@href").string()    #if nexturl:    #   nexturl2 = re_search_once("(.+)html", nexturl)    #   nexturl2 = nexturl2+"html"    #   session.queue(Request(nexturl2), process_view_category, { } ) def process_view_product(data, context, session):    product = Product()    product.category = 'Harmonicas'    product.name = context['name']     product.url = context['url']    product.ssid = product.name    for imgs in data.xpath("//img[contains(@src,'.jpg')]"):        img = imgs.xpath("(.)/@src").string()        if img:           product.properties.append(ProductProperty(type="image" , value = {'src': img}))    review = Review()      review.product = product.name       review.url = product.url       review.ssid = product.ssid        author = data.xpath("//p[contains(text(),'email:')]/preceding::p[1]/text()").string()    if author:       review.authors.append(Person(name = author, ssid = review.ssid))       review.date = "N/A"    exc = data.xpath("//p/text()").string(multiple=True)    if exc:       review.properties.append(ReviewProperty(type="excerpt", value = exc ))                                   review.type = 'pro'    product.reviews.append(review)     session.emit(product)def run(context, session):    session.queue(Request('http://www.patmissin.com/reviews/reviews.html'), process_view_category, { } )